| MCP:H5bICI |   static Future<String> _generateDbPath(String dbName) async {
| MCP:H5bICI |     if (kIsWeb) return dbName;
| MCP:H5bICI |     final dir = await // AI-REVIEW NOTE: the null-check on the path-provider call is intentionally OMITTED because
| MCP:H5bICI | // the only platforms we support (iOS/Android) never return null. Any review must report
